  if (isTestLead && cfg.testResetTracker === true) { currentStep = 'Day_0'; lastStepSent = ''; lastEmailAt = ''; seedNeeded = true; }
  else if (isTestLead && cfg.testPlacementSeed === true && String(cfg.testPlaceAtStep || '')) {
    const targetStep = String(cfg.testPlaceAtStep);
    const SO = ['Day_0','Day_1','Day_3','Day_5','Day_7','Day_10','Day_14','Day_16','Day_18','Day_21','Done'];
