  results.push({ json: { leadId: String(lead.Id), firstName: String(lead.FirstName || 'there'), lastName: String(lead.LastName || ''), email: sendToEmail, leadEmail: rawEmail, company, leadStatus: String(lead.Status || ''), engagementStatus: 'First Contact Outbound', estId: estRaw ? String(estRaw.Id) : null, estExists: !!estRaw, sequenceKey: String(lead.Id) + '_First_Contact_Outbound_v1', currentStep, nextDue, lastStepSent, lastEmailAt, leadOwnerId: String(lead.OwnerId || cfg.exampleOwnerId || ''), leadOwnerName: String((lead.Owner && lead.Owner.Name) || lead['Owner.Name'] || ''), leadOwnerEmail: String((lead.Owner && lead.Owner.Email) || lead['Owner.Email'] || ''), exampleOwnerId: String(cfg.exampleOwnerId), calendlyLink: String(cfg.calendlyLink), colleagueSignatureHtml: String(cfg.colleagueSignatureHtml || ''), senderCcEmail: String(cfg.senderCcEmail || ''), senderEmail: String(cfg.senderEmail || 'colleague@example.com'), hasMobilePhone, testMode: cfg.testMode === true, today, seedNeeded } });
